{
  "family": "Wolff-Kishner Reduction",
  "candidate": {
    "substrate_smiles": [
      "O=C(C)CC"
    ],
    "product_smiles": [
      "CCCC"
    ],
    "optional_reagent_smiles": [
      "NN",
      "[OH-].[K+]"
    ],
    "rationale": "This reaction shows the reduction of a simple, acyclic ketone (2-butanone) to its corresponding alkane (n-butane) using hydrazine (NN) and potassium hydroxide ([OH-].[K+]), which are the classic reagents for the Wolff-Kishner reduction. The transformation is a clear deoxygenation of a carbonyl group to a methylene group, which is the defining feature of this reaction. The substrates and products are small, acyclic, and lack complex functional groups, making it a canonical and unambiguous example.",
    "collision_avoidance_note": "This example uses a simple aliphatic ketone to avoid overlap with reactions involving aromatic systems (e.g., Friedel-Crafts acylation followed by reduction) or other carbonyl reductions that proceed under different conditions (e.g., Clemmensen reduction, which is acid-catalyzed). The simplicity of the substrate focuses squarely on the C=O to CH2 transformation characteristic of the Wolff-Kishner reduction."
  }
}
